INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (1, 'en', 'cookie-policy', 'Cookie Policy', '<p><strong>Last Updated:</strong> <span>25.12.2024</span></p>\n<h2>What are cookies?</h2>\n<p><strong>Cookies</strong> are small text files that are stored on your device (computer, tablet, smartphone) when you visit websites. They allow the site to remember information about you, such as your preferences or login data, and use it during future visits.</p>\n<h2>What types of cookies do we use?</h2>\n<p>We use the following types of cookies:</p>\n<h3>Functional cookies</h3>\n<p>These files help the Site remember your preferences (such as language, region) and provide a personalized experience.</p>\n<h3>Analytical cookies</h3>\n<p>We use analytical tools (such as Google Analytics) to collect information on how users interact with the Site. This helps us improve the structure and content of the Site. All data is collected in an anonymous form.</p>\n<h3>Advertising cookies</h3>\n<p>These cookies are used to display relevant ads based on your interests and behavior on the Site. We may share this data with partner advertising networks.</p>\n<h2>Third-party cookies</h2>\n<p>Some cookies may be set by third parties (such as analytics services or advertising partners). We do not control the collection and use of this data. Details on the use of such files can be found in the privacy policies of the respective third-party services.</p>\n<h2>How to manage cookies?</h2>\n<p>You can change your cookie preferences in your browser settings:</p>\n<ul>\n      <li><strong>Google Chrome:</strong> Settings → Privacy and security → Cookies and other site data</li>\n      <li><strong>Mozilla Firefox:</strong> Settings → Privacy & Security</li>\n      <li><strong>Safari:</strong> Preferences → Privacy</li>\n      <li><strong>Microsoft Edge:</strong> Settings → Cookies and site permissions</li>\n</ul>\n<p>You can also delete already saved cookies and configure your browser to block their installation. However, disabling essential cookies may lead to some Site functions working incorrectly.</p>\n<h2>Consent to the use of cookies</h2>\n<p>Upon your first visit to the Site, we request your consent to the use of cookies. If you continue to use the Site without changing your settings, we assume you agree to the use of cookies.</p>\n<h2>Policy Updates</h2>\n<p>We reserve the right to update this Policy at any time. The new version takes effect from the moment it is published on the Site.</p>\n<h2>Contact Information</h2>\n<p>If you have any questions about the use of cookies, please contact us through the special form: <a href=\"https://ciphersonline.com/contact\" target=\"_blank\">https://ciphersonline.com/contact</a></p>\n<p>This Cookie Policy is an integral part of our <a href=\"https://ciphersonline.com/privacy-policy\" target=\"_blank\">Privacy Policy</a>.</p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (2, 'es', 'cookie-policy', 'Política de Cookies', '<p><strong>Última actualización:</strong> <span>25.12.2024</span></p>\n<h2>¿Qué son las cookies?</h2>\n<p><strong>Las cookies</strong> son pequeños archivos de texto que se almacenan en su dispositivo (ordenador, tableta, teléfono inteligente) cuando visita sitios web. Permiten que el sitio recuerde información sobre usted, como sus preferencias o datos de inicio de sesión, y la utilice en futuras visitas.</p>\n<h2>¿Qué tipos de cookies utilizamos?</h2>\n<p>Utilizamos los siguientes tipos de cookies:</p>\n<h3>Cookies funcionales</h3>\n<p>Estos archivos ayudan al Sitio a recordar sus preferencias (como el idioma o la región) y proporcionan una experiencia personalizada.</p>\n<h3>Cookies analíticas</h3>\n<p>Utilizamos herramientas analíticas (como Google Analytics) para recopilar información sobre cómo los usuarios interactúan con el Sitio. Esto nos ayuda a mejorar la estructura y el contenido del Sitio. Todos los datos se recopilan de forma anónima.</p>\n<h3>Cookies publicitarias</h3>\n<p>Estas cookies se utilizan para mostrar anuncios relevantes basados en sus intereses y comportamiento en el Sitio. Podemos compartir estos datos con redes publicitarias asociadas.</p>\n<h2>Cookies de terceros</h2>\n<p>Algunas cookies pueden ser establecidas por terceros (como servicios de análisis o socios publicitarios). No controlamos la recopilación y el uso de estos datos. Los detalles sobre el uso de dichos archivos se encuentran en las políticas de privacidad de los respectivos servicios de terceros.</p>\n<h2>¿Cómo gestionar las cookies?</h2>\n<p>Puede cambiar sus preferencias de cookies en la configuración de su navegador:</p>\n<ul>\n      <li><strong>Google Chrome:</strong> Configuración → Privacidad y seguridad → Cookies y otros datos del sitio</li>\n      <li><strong>Mozilla Firefox:</strong> Configuración → Privacidad y seguridad</li>\n      <li><strong>Safari:</strong> Preferencias → Privacidad</li>\n      <li><strong>Microsoft Edge:</strong> Configuración → Cookies y permisos del sitio</li>\n</ul>\n<p>También puede eliminar las cookies ya guardadas y configurar su navegador para bloquear su instalación. Sin embargo, desactivar las cookies esenciales puede provocar que algunas funciones del Sitio no funcionen correctamente.</p>\n<h2>Consentimiento para el uso de cookies</h2>\n<p>En su primera visita al Sitio, solicitamos su consentimiento para el uso de cookies. Si continúa utilizando el Sitio sin cambiar su configuración, asumimos que acepta el uso de cookies.</p>\n<h2>Actualizaciones de la política</h2>\n<p>Nos reservamos el derecho de actualizar esta Política en cualquier momento. La nueva versión entra en vigor desde el momento en que se publica en el Sitio.</p>\n<h2>Información de contacto</h2>\n<p>Si tiene alguna pregunta sobre el uso de cookies, por favor contáctenos a través del formulario especial: <a href=\"https://ciphersonline.com/es/contact\" target=\"_blank\">https://ciphersonline.com/es/contact</a></p>\n<p>Esta Política de Cookies es una parte integral de nuestra <a href=\"https://ciphersonline.com/es/privacy-policy\" target=\"_blank\">Política de Privacidad</a>.</p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (3, 'pt', 'cookie-policy', 'Política de Cookies', '<p><strong>Última atualização:</strong> <span>25.12.2024</span></p>\n<h2>O que são cookies?</h2>\n<p><strong>Cookies</strong> são pequenos arquivos de texto que são armazenados no seu dispositivo (computador, tablet, smartphone) quando você visita sites. Eles permitem que o site se lembre de informações sobre você, como suas preferências ou dados de login, e as utilize em visitas futuras.</p>\n<h2>Que tipos de cookies utilizamos?</h2>\n<p>Utilizamos os seguintes tipos de cookies:</p>\n<h3>Cookies funcionais</h3>\n<p>Esses arquivos ajudam o Site a lembrar suas preferências (como idioma ou região) e oferecem uma experiência personalizada.</p>\n<h3>Cookies analíticos</h3>\n<p>Utilizamos ferramentas analíticas (como Google Analytics) para coletar informações sobre como os usuários interagem com o Site. Isso nos ajuda a melhorar a estrutura e o conteúdo do Site. Todos os dados são coletados de forma anônima.</p>\n<h3>Cookies de publicidade</h3>\n<p>Esses cookies são usados para exibir anúncios relevantes com base nos seus interesses e comportamento no Site. Podemos compartilhar esses dados com redes de publicidade parceiras.</p>\n<h2>Cookies de terceiros</h2>\n<p>Alguns cookies podem ser configurados por terceiros (como serviços de análise ou parceiros de publicidade). Não controlamos a coleta e o uso desses dados. Os detalhes sobre o uso desses arquivos podem ser encontrados nas políticas de privacidade dos respectivos serviços de terceiros.</p>\n<h2>Como gerenciar cookies?</h2>\n<p>Você pode alterar suas preferências de cookies nas configurações do seu navegador:</p>\n<ul>\n      <li><strong>Google Chrome:</strong> Configurações → Privacidade e segurança → Cookies e outros dados do site</li>\n      <li><strong>Mozilla Firefox:</strong> Configurações → Privacidade e segurança</li>\n      <li><strong>Safari:</strong> Preferências → Privacidade</li>\n      <li><strong>Microsoft Edge:</strong> Configurações → Cookies e permissões do site</li>\n</ul>\n<p>Você também pode excluir os cookies já salvos e configurar seu navegador para bloquear a instalação de novos cookies. No entanto, desativar cookies essenciais pode fazer com que algumas funções do Site não funcionem corretamente.</p>\n<h2>Consentimento para o uso de cookies</h2>\n<p>Na sua primeira visita ao Site, solicitamos seu consentimento para o uso de cookies. Se você continuar a usar o Site sem alterar as configurações, presumimos que você concorda com o uso de cookies.</p>\n<h2>Atualizações da política</h2>\n<p>Reservamo-nos o direito de atualizar esta Política a qualquer momento. A nova versão entra em vigor a partir do momento em que é publicada no Site.</p>\n<h2>Informações de contato</h2>\n<p>Se você tiver alguma dúvida sobre o uso de cookies, entre em contato conosco através do formulário especial: <a href=\"https://ciphersonline.com/pt/contact\" target=\"_blank\">https://ciphersonline.com/pt/contact</a></p>\n<p>Esta Política de Cookies é parte integrante da nossa <a href=\"https://ciphersonline.com/pt/privacy-policy\" target=\"_blank\">Política de Privacidade</a>.</p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (4, 'ru', 'cookie-policy', 'Политика использования Cookie', '<p><strong>Дата последнего обновления:</strong> <span>25.12.2024</span></p>\n<h2>Что такое cookie?</h2>\n<p><strong>Cookie</strong> – это небольшие текстовые файлы, которые сохраняются на вашем устройстве (компьютере, планшете, смартфоне) при посещении веб-сайтов. Они позволяют сайту запоминать информацию о вас, например, ваши предпочтения или данные для входа, и использовать её при последующих посещениях.</p>\n<h2>Какие cookie мы используем?</h2>\n<p>Мы используем следующие типы файлов cookie:</p>\n<h3>Функциональные cookie</h3>\n<p>Эти файлы помогают Сайту запоминать ваши предпочтения (например, язык, регион) и обеспечивать персонализированный опыт.</p>\n<h3>Аналитические cookie</h3>\n<p>Мы используем аналитические инструменты (например, Google Analytics) для сбора информации о том, как пользователи взаимодействуют с Сайтом. Это позволяет нам улучшать структуру и содержание Сайта. Все данные собираются в анонимной форме.</p>\n<h3>Рекламные cookie</h3>\n<p>Эти cookie используются для отображения релевантной рекламы на основе ваших интересов и поведения на Сайте. Мы можем делиться этими данными с партнёрскими рекламными сетями.</p>\n<h2>Сторонние cookie</h2>\n<p>Некоторые cookie могут быть установлены третьими сторонами (например, сервисами аналитики, рекламными партнёрами). Мы не контролируем сбор и использование этих данных. Подробности об использовании таких файлов можно найти в политиках конфиденциальности соответствующих сторонних сервисов.</p>\n<h2>Как управлять cookie?</h2>\n<p>Вы можете изменить настройки использования cookie в вашем браузере:</p>\n<ul>\n      <li><strong>Google Chrome:</strong> Настройки → Конфиденциальность и безопасность → Файлы cookie и другие данные сайтов</li>\n      <li><strong>Mozilla Firefox:</strong> Настройки → Приватность и защита</li>\n      <li><strong>Safari:</strong> Настройки → Конфиденциальность</li>\n      <li><strong>Microsoft Edge:</strong> Настройки → Файлы cookie и разрешения сайта</li>\n</ul>\n<p>Вы также можете удалить уже сохранённые cookie и настроить браузер на блокировку их установки. Однако, отключение обязательных cookie может привести к некорректной работе некоторых функций Сайта.</p>\n<h2>Согласие на использование cookie</h2>\n<p>При первом посещении Сайта мы запрашиваем ваше согласие на использование файлов cookie. Если вы продолжаете использовать Сайт без изменения настроек, мы считаем, что вы согласны с использованием cookie.</p>\n<h2>Обновления Политики</h2>\n<p>Мы оставляем за собой право обновлять настоящую Политику в любое время. Новая редакция вступает в силу с момента её публикации на Сайте.</p>\n<h2>Контактная информация</h2>\n<p>Если у вас есть вопросы по поводу использования файлов cookie, свяжитесь с нами через специальную форму: <a href=\"https://ciphersonline.com/ru/contact\" target=\"_blank\">https://ciphersonline.com/ru/contact</a></p>\n<p>Данная Политика cookie является неотъемлемой частью нашей <a href=\"https://ciphersonline.com/ru/privacy-policy\" target=\"_blank\">Политики конфиденциальности</a>.</p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (5, 'tr', 'cookie-policy', 'Çerez Politikası', '<p><strong>Son Güncelleme Tarihi:</strong> <span>25.12.2024</span></p>\n<h2>Çerezler nedir?</h2>\n<p><strong>Çerezler</strong>, web sitelerini ziyaret ettiğinizde cihazınıza (bilgisayar, tablet, akıllı telefon) kaydedilen küçük metin dosyalarıdır. Bu dosyalar, siteye giriş bilgileri veya tercihlerinizi hatırlayarak sonraki ziyaretlerde kullanılmasını sağlar.</p>\n<h2>Hangi tür çerezleri kullanıyoruz?</h2>\n<p>Aşağıdaki türde çerezleri kullanıyoruz:</p>\n<h3>Fonksiyonel çerezler</h3>\n<p>Bu çerezler, sitenin tercihlerinizi (örneğin dil veya bölge) hatırlamasına yardımcı olur ve kişiselleştirilmiş bir deneyim sağlar.</p>\n<h3>Analitik çerezler</h3>\n<p>Kullanıcıların siteyle nasıl etkileşimde bulunduğuna dair bilgi toplamak için analiz araçları (örneğin Google Analytics) kullanıyoruz. Bu, sitenin yapısını ve içeriğini geliştirmemize yardımcı olur. Tüm veriler anonim olarak toplanır.</p>\n<h3>Reklam çerezleri</h3>\n<p>Bu çerezler, ilgi alanlarınıza ve site üzerindeki davranışlarınıza göre ilgili reklamların gösterilmesi için kullanılır. Bu verileri iş ortaklarımızla paylaşabiliriz.</p>\n<h2>Üçüncü taraf çerezleri</h2>\n<p>Bazı çerezler, üçüncü taraflar (örneğin analiz servisleri veya reklam ortakları) tarafından yerleştirilebilir. Bu verilerin toplanması ve kullanılması üzerinde kontrolümüz yoktur. Bu tür dosyaların kullanımıyla ilgili ayrıntılar, ilgili üçüncü tarafların gizlilik politikalarında bulunabilir.</p>\n<h2>Çerezleri nasıl yönetebilirsiniz?</h2>\n<p>Tarayıcınızın ayarlarından çerez tercihlerinizi değiştirebilirsiniz:</p>\n<ul>\n      <li><strong>Google Chrome:</strong> Ayarlar → Gizlilik ve güvenlik → Çerezler ve diğer site verileri</li>\n      <li><strong>Mozilla Firefox:</strong> Ayarlar → Gizlilik ve güvenlik</li>\n      <li><strong>Safari:</strong> Tercihler → Gizlilik</li>\n      <li><strong>Microsoft Edge:</strong> Ayarlar → Çerezler ve site izinleri</li>\n</ul>\n<p>Ayrıca, zaten kaydedilmiş çerezleri silebilir ve tarayıcınızı çerezlerin yüklenmesini engelleyecek şekilde yapılandırabilirsiniz. Ancak, zorunlu çerezlerin devre dışı bırakılması, bazı site işlevlerinin düzgün çalışmamasına neden olabilir.</p>\n<h2>Çerezlerin kullanımı için onay</h2>\n<p>Sitemizi ilk ziyaretinizde çerezlerin kullanımı için onayınızı istiyoruz. Ayarlarınızı değiştirmeden siteyi kullanmaya devam ederseniz, çerezlerin kullanılmasını kabul ettiğiniz varsayılır.</p>\n<h2>Politika Güncellemeleri</h2>\n<p>Bu politikayı herhangi bir zamanda güncelleme hakkımız saklıdır. Yeni sürüm, sitede yayınlandığı andan itibaren geçerli olacaktır.</p>\n<h2>İletişim Bilgileri</h2>\n<p>Çerezlerin kullanımıyla ilgili herhangi bir sorunuz varsa, lütfen şu form aracılığıyla bizimle iletişime geçin: <a href=\"https://ciphersonline.com/tr/contact\" target=\"_blank\">https://ciphersonline.com/tr/contact</a></p>\n<p>Bu Çerez Politikası, <a href=\"https://ciphersonline.com/tr/privacy-policy\" target=\"_blank\">Gizlilik Politikamızın</a> ayrılmaz bir parçasıdır.</p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (6, 'fr', 'cookie-policy', 'Politique de Cookies', '<p><strong>Dernière mise à jour :</strong> <span>25.12.2024</span></p>\n<h2>Qu\'est-ce que les cookies ?</h2>\n<p><strong>Les cookies</strong> sont de petits fichiers texte qui sont stockés sur votre appareil (ordinateur, tablette, smartphone) lorsque vous visitez des sites web. Ils permettent au site de se souvenir d\'informations vous concernant, telles que vos préférences ou vos identifiants de connexion, et de les utiliser lors de vos visites futures.</p>\n<h2>Quels types de cookies utilisons-nous ?</h2>\n<p>Nous utilisons les types de cookies suivants :</p>\n<h3>Cookies fonctionnels</h3>\n<p>Ces cookies permettent au site de mémoriser vos préférences (comme la langue ou la région) et d\'offrir une expérience personnalisée.</p>\n<h3>Cookies analytiques</h3>\n<p>Nous utilisons des outils d\'analyse (comme Google Analytics) pour collecter des informations sur la manière dont les utilisateurs interagissent avec le site. Cela nous aide à améliorer la structure et le contenu du site. Toutes les données sont collectées de manière anonyme.</p>\n<h3>Cookies publicitaires</h3>\n<p>Ces cookies sont utilisés pour afficher des publicités pertinentes en fonction de vos intérêts et de votre comportement sur le site. Nous pouvons partager ces données avec des réseaux publicitaires partenaires.</p>\n<h2>Cookies tiers</h2>\n<p>Certains cookies peuvent être placés par des tiers (tels que des services d\'analyse ou des partenaires publicitaires). Nous n\'exerçons aucun contrôle sur la collecte et l\'utilisation de ces données. Les détails sur l\'utilisation de ces fichiers sont disponibles dans les politiques de confidentialité des services tiers respectifs.</p>\n<h2>Comment gérer les cookies ?</h2>\n<p>Vous pouvez modifier vos préférences de cookies dans les paramètres de votre navigateur :</p>\n<ul>\n      <li><strong>Google Chrome :</strong> Paramètres → Confidentialité et sécurité → Cookies et autres données de site</li>\n      <li><strong>Mozilla Firefox :</strong> Paramètres → Vie privée et sécurité</li>\n      <li><strong>Safari :</strong> Préférences → Confidentialité</li>\n      <li><strong>Microsoft Edge :</strong> Paramètres → Cookies et autorisations de site</li>\n</ul>\n<p>Vous pouvez également supprimer les cookies déjà enregistrés et configurer votre navigateur pour bloquer leur installation. Cependant, la désactivation des cookies essentiels peut entraîner un dysfonctionnement de certaines fonctionnalités du site.</p>\n<h2>Consentement à l\'utilisation des cookies</h2>\n<p>Lors de votre première visite sur le site, nous demandons votre consentement pour l\'utilisation des cookies. Si vous continuez à utiliser le site sans modifier vos paramètres, nous considérons que vous acceptez l\'utilisation des cookies.</p>\n<h2>Mises à jour de la politique</h2>\n<p>Nous nous réservons le droit de mettre à jour cette politique à tout moment. La nouvelle version entre en vigueur dès sa publication sur le site.</p>\n<h2>Informations de contact</h2>\n<p>Si vous avez des questions concernant l\'utilisation des cookies, veuillez nous contacter via le formulaire dédié : <a href=\"https://ciphersonline.com/fr/contact\" target=\"_blank\">https://ciphersonline.com/fr/contact</a></p>\n<p>Cette Politique de Cookies fait partie intégrante de notre <a href=\"https://ciphersonline.com/fr/privacy-policy\" target=\"_blank\">Politique de Confidentialité</a>.</p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (7, 'de', 'cookie-policy', 'Cookie-Richtlinie', '<p><strong>Letzte Aktualisierung:</strong> <span>25.12.2024</span></p>\n<h2>Was sind Cookies?</h2>\n<p><strong>Cookies</strong> sind kleine Textdateien, die auf Ihrem Gerät (Computer, Tablet, Smartphone) gespeichert werden, wenn Sie Websites besuchen. Sie ermöglichen es der Website, sich an Informationen über Sie zu erinnern, wie z.B. Ihre Präferenzen oder Anmeldedaten, und diese bei zukünftigen Besuchen zu verwenden.</p>\n<h2>Welche Arten von Cookies verwenden wir?</h2>\n<p>Wir verwenden die folgenden Arten von Cookies:</p>\n<h3>Funktionale Cookies</h3>\n<p>Diese Cookies helfen der Website, sich an Ihre Präferenzen (z.B. Sprache oder Region) zu erinnern und eine personalisierte Erfahrung zu bieten.</p>\n<h3>Analytische Cookies</h3>\n<p>Wir verwenden Analysetools (wie Google Analytics), um Informationen darüber zu sammeln, wie Benutzer mit der Website interagieren. Dies hilft uns, die Struktur und den Inhalt der Website zu verbessern. Alle Daten werden anonym erfasst.</p>\n<h3>Werbe-Cookies</h3>\n<p>Diese Cookies werden verwendet, um relevante Werbung basierend auf Ihren Interessen und Ihrem Verhalten auf der Website anzuzeigen. Wir können diese Daten mit Partner-Werbenetzwerken teilen.</p>\n<h2>Cookies von Drittanbietern</h2>\n<p>Einige Cookies können von Drittanbietern (wie Analyse- oder Werbediensten) gesetzt werden. Wir haben keine Kontrolle über die Erhebung und Nutzung dieser Daten. Einzelheiten zur Nutzung solcher Dateien finden Sie in den Datenschutzrichtlinien der jeweiligen Drittanbieter.</p>\n<h2>Wie kann man Cookies verwalten?</h2>\n<p>Sie können Ihre Cookie-Einstellungen in den Einstellungen Ihres Browsers ändern:</p>\n<ul>\n      <li><strong>Google Chrome:</strong> Einstellungen → Datenschutz und Sicherheit → Cookies und andere Websitedaten</li>\n      <li><strong>Mozilla Firefox:</strong> Einstellungen → Datenschutz & Sicherheit</li>\n      <li><strong>Safari:</strong> Einstellungen → Datenschutz</li>\n      <li><strong>Microsoft Edge:</strong> Einstellungen → Cookies und Website-Berechtigungen</li>\n</ul>\n<p>Sie können auch bereits gespeicherte Cookies löschen und Ihren Browser so einstellen, dass deren Installation blockiert wird. Das Deaktivieren von essenziellen Cookies kann jedoch dazu führen, dass einige Funktionen der Website nicht ordnungsgemäß funktionieren.</p>\n<h2>Zustimmung zur Verwendung von Cookies</h2>\n<p>Bei Ihrem ersten Besuch auf der Website bitten wir um Ihre Zustimmung zur Verwendung von Cookies. Wenn Sie die Website weiterhin ohne Änderungen Ihrer Einstellungen nutzen, gehen wir davon aus, dass Sie der Verwendung von Cookies zustimmen.</p>\n<h2>Aktualisierungen der Richtlinie</h2>\n<p>Wir behalten uns das Recht vor, diese Richtlinie jederzeit zu aktualisieren. Die neue Version tritt in Kraft, sobald sie auf der Website veröffentlicht wird.</p>\n<h2>Kontaktinformationen</h2>\n<p>Wenn Sie Fragen zur Verwendung von Cookies haben, kontaktieren Sie uns bitte über das spezielle Formular: <a href=\"https://ciphersonline.com/de/contact\" target=\"_blank\">https://ciphersonline.com/de/contact</a></p>\n<p>Diese Cookie-Richtlinie ist integraler Bestandteil unserer <a href=\"https://ciphersonline.com/de/privacy-policy\" target=\"_blank\">Datenschutzrichtlinie</a>.</p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (8, 'it', 'cookie-policy', 'Politica sui Cookie', '<p><strong>Ultimo aggiornamento:</strong> <span>25.12.2024</span></p>\n<h2>Cosa sono i cookie?</h2>\n<p><strong>I cookie</strong> sono piccoli file di testo che vengono memorizzati sul tuo dispositivo (computer, tablet, smartphone) quando visiti siti web. Consentono al sito di ricordare informazioni su di te, come le tue preferenze o i dati di accesso, e di utilizzarle durante le visite future.</p>\n<h2>Quali tipi di cookie utilizziamo?</h2>\n<p>Utilizziamo i seguenti tipi di cookie:</p>\n<h3>Cookie funzionali</h3>\n<p>Questi cookie aiutano il sito a ricordare le tue preferenze (come la lingua o la regione) e a offrire un\'esperienza personalizzata.</p>\n<h3>Cookie analitici</h3>\n<p>Utilizziamo strumenti di analisi (come Google Analytics) per raccogliere informazioni su come gli utenti interagiscono con il sito. Questo ci aiuta a migliorare la struttura e i contenuti del sito. Tutti i dati vengono raccolti in forma anonima.</p>\n<h3>Cookie pubblicitari</h3>\n<p>Questi cookie vengono utilizzati per mostrare annunci pertinenti in base ai tuoi interessi e al tuo comportamento sul sito. Possiamo condividere questi dati con reti pubblicitarie partner.</p>\n<h2>Cookie di terze parti</h2>\n<p>Alcuni cookie possono essere impostati da terze parti (come servizi di analisi o partner pubblicitari). Non controlliamo la raccolta e l\'utilizzo di questi dati. I dettagli sull\'uso di tali file sono disponibili nelle politiche sulla privacy dei rispettivi servizi di terze parti.</p>\n<h2>Come gestire i cookie?</h2>\n<p>Puoi modificare le tue preferenze sui cookie nelle impostazioni del tuo browser:</p>\n<ul>\n      <li><strong>Google Chrome:</strong> Impostazioni → Privacy e sicurezza → Cookie e altri dati dei siti</li>\n      <li><strong>Mozilla Firefox:</strong> Impostazioni → Privacy e sicurezza</li>\n      <li><strong>Safari:</strong> Preferenze → Privacy</li>\n      <li><strong>Microsoft Edge:</strong> Impostazioni → Cookie e autorizzazioni per i siti</li>\n</ul>\n<p>Puoi anche eliminare i cookie già salvati e configurare il browser per bloccarne l\'installazione. Tuttavia, disattivare i cookie essenziali potrebbe comportare il malfunzionamento di alcune funzionalità del sito.</p>\n<h2>Consenso all\'uso dei cookie</h2>\n<p>Alla tua prima visita al sito, richiediamo il tuo consenso all\'uso dei cookie. Se continui a utilizzare il sito senza modificare le impostazioni, presumiamo che tu accetti l\'uso dei cookie.</p>\n<h2>Aggiornamenti della politica</h2>\n<p>Ci riserviamo il diritto di aggiornare questa politica in qualsiasi momento. La nuova versione entra in vigore non appena viene pubblicata sul sito.</p>\n<h2>Informazioni di contatto</h2>\n<p>Se hai domande sull\'uso dei cookie, ti invitiamo a contattarci tramite il modulo dedicato: <a href=\"https://ciphersonline.com/it/contact\" target=\"_blank\">https://ciphersonline.com/it/contact</a></p>\n<p>Questa Politica sui Cookie è parte integrante della nostra <a href=\"https://ciphersonline.com/it/privacy-policy\" target=\"_blank\">Informativa sulla Privacy</a>.</p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (9, 'en', 'privacy-policy', 'Privacy Policy', '<p><strong>Last Updated:</strong> 25.12.2024</p>\n<p>The ciphersonline.com website (hereinafter referred to as the “Website”) respects your privacy and takes all necessary measures to protect personal data in accordance with the General Data Protection Regulation (GDPR, Regulation (EU) 2016/679). This Privacy Policy explains what data we collect, how it is used, and what rights you have regarding your personal data.</p>\n\n<h2>Who we are</h2>\n<p>\n      Data Controller: BRUKVA PR <br>\n      Email: <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>  \n      Address: MITE RUŽIĆA 2, NOVI SAD, SERBIA\n</p>\n\n<h2>What data we collect</h2>\n<p>We may collect and process the following data:</p>\n<ul>\n      <li><strong>Identification data</strong>: first name, last name, email, phone number.</li>\n      <li><strong>Authorization data</strong>: username, password (encrypted).</li>\n      <li><strong>Technical data</strong>: IP address, browser and device data, operating system, geolocation, log data.</li>\n      <li><strong>Activity data</strong>: visit history, interaction with content, and actions on the Website.</li>\n      <li><strong>Cookies and similar technologies</strong>: to ensure the functionality of the Website and analyze user behavior (details in the Cookie Policy).</li>\n</ul>\n\n<h2>Legal basis for processing</h2>\n<p>We process your personal data based on the following legal grounds:</p>\n<ul>\n      <li><strong>Your consent</strong> – when subscribing to newsletters or registering on the Website.</li>\n      <li><strong>Contract performance</strong> – data processing is necessary to provide services (e.g., processing orders and messages).</li>\n      <li><strong>Legitimate interests</strong> – to protect our rights and interests, ensure security, and improve the Website.</li>\n      <li><strong>Legal obligations</strong> – when we are required to retain or provide data by law.</li>\n</ul>\n\n<h2>How we use your data</h2>\n<p>We use personal data for the following purposes:</p>\n<ul>\n      <li>To provide access to the Website and its functionality.</li>\n      <li>To contact you regarding inquiries submitted through forms on the Website.</li>\n      <li>To analyze and improve the performance and user experience of the Website.</li>\n      <li>To comply with our legal obligations and protect against fraud.</li>\n</ul>\n\n<h2>Sharing data with third parties</h2>\n<p>We do not share your personal data with third parties without your consent, except as required by law. Your data may be transferred to technical contractors to ensure the operation of the Website (e.g., hosting providers or analytics services).</p>\n\n<h2>Data retention period</h2>\n<p>Your data is stored for as long as necessary to fulfill the purposes of processing or meet legal obligations.</p>\n\n<h2>Your rights</h2>\n<p>You have the right to:</p>\n<ul>\n      <li>Request access to your personal data.</li>\n      <li>Correct your data.</li>\n      <li>Request the deletion of your data (\"right to be forgotten\").</li>\n      <li>Restrict the processing of your data.</li>\n      <li>Withdraw consent to data processing.</li>\n</ul>\n<p>To exercise these rights, contact us at <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>.</p>\n\n<h2>Data security</h2>\n<p>We take reasonable measures to protect your data from unauthorized access, loss, or alteration. However, data transmission over the Internet is not completely secure, and we cannot guarantee absolute protection.</p>\n\n<h2>Use of cookies</h2>\n<p>We use cookies to operate the Website and provide a personalized experience. More information on cookies and how to manage them can be found in our <a href=\"https://ciphersonline.com/cookie-policy\">Cookie Policy</a>.</p>\n\n<h2>Links to third-party resources</h2>\n<p>Our Website may contain links to third-party sites. We do not control their privacy policies and recommend reviewing their terms separately.</p>\n\n<h2>Changes to the privacy policy</h2>\n<p>We reserve the right to update this Privacy Policy at any time. Any changes will be published on this page. Please check this page periodically to stay informed of updates.</p>\n\n<h2>Contact information</h2>\n<p>If you have any questions regarding this Privacy Policy or the processing of your data, please contact us at <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a></p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (10, 'es', 'privacy-policy', 'Política de Privacidad', '<p><strong>Última actualización:</strong> 25.12.2024</p>\n<p>El sitio web ciphersonline.com (en adelante denominado el “Sitio web”) respeta su privacidad y toma todas las medidas necesarias para proteger los datos personales de acuerdo con el Reglamento General de Protección de Datos (GDPR, Reglamento (UE) 2016/679). Esta Política de Privacidad explica qué datos recopilamos, cómo se utilizan y qué derechos tiene con respecto a sus datos personales.</p>\n\n<h2>Quiénes somos</h2>\n<p>\n      Responsable del tratamiento de datos: BRUKVA PR <br>\n      Correo electrónico: <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>  \n      Dirección: MITE RUŽIĆA 2, NOVI SAD, SERBIA\n</p>\n\n<h2>Qué datos recopilamos</h2>\n<p>Podemos recopilar y procesar los siguientes datos:</p>\n<ul>\n      <li><strong>Datos de identificación</strong>: nombre, apellidos, correo electrónico, número de teléfono.</li>\n      <li><strong>Datos de autorización</strong>: nombre de usuario, contraseña (encriptada).</li>\n      <li><strong>Datos técnicos</strong>: dirección IP, datos del navegador y del dispositivo, sistema operativo, geolocalización, datos de registro.</li>\n      <li><strong>Datos de actividad</strong>: historial de visitas, interacción con el contenido y acciones en el Sitio web.</li>\n      <li><strong>Cookies y tecnologías similares</strong>: para garantizar la funcionalidad del Sitio web y analizar el comportamiento del usuario (detalles en la Política de Cookies).</li>\n</ul>\n\n<h2>Base legal para el tratamiento</h2>\n<p>Tratamos sus datos personales sobre la base de los siguientes fundamentos legales:</p>\n<ul>\n      <li><strong>Su consentimiento</strong> – al suscribirse a boletines informativos o registrarse en el Sitio web.</li>\n      <li><strong>Ejecución de un contrato</strong> – el procesamiento de datos es necesario para proporcionar servicios (por ejemplo, procesamiento de pedidos y mensajes).</li>\n      <li><strong>Intereses legítimos</strong> – para proteger nuestros derechos e intereses, garantizar la seguridad y mejorar el Sitio web.</li>\n      <li><strong>Obligaciones legales</strong> – cuando estamos obligados a retener o proporcionar datos por ley.</li>\n</ul>\n\n<h2>Cómo usamos sus datos</h2>\n<p>Utilizamos los datos personales para los siguientes fines:</p>\n<ul>\n      <li>Proporcionar acceso al Sitio web y a sus funcionalidades.</li>\n      <li>Contactarlo con respecto a consultas enviadas a través de formularios en el Sitio web.</li>\n      <li>Analizar y mejorar el rendimiento y la experiencia del usuario en el Sitio web.</li>\n      <li>Cumplir con nuestras obligaciones legales y protegernos contra el fraude.</li>\n</ul>\n\n<h2>Compartición de datos con terceros</h2>\n<p>No compartimos sus datos personales con terceros sin su consentimiento, excepto cuando lo exige la ley. Sus datos pueden ser transferidos a contratistas técnicos para garantizar el funcionamiento del Sitio web (por ejemplo, proveedores de alojamiento o servicios de análisis).</p>\n\n<h2>Período de retención de datos</h2>\n<p>Sus datos se almacenan durante el tiempo necesario para cumplir con los fines del procesamiento o para cumplir con las obligaciones legales.</p>\n\n<h2>Sus derechos</h2>\n<p>Usted tiene derecho a:</p>\n<ul>\n      <li>Solicitar acceso a sus datos personales.</li>\n      <li>Corregir sus datos.</li>\n      <li>Solicitar la eliminación de sus datos (\"derecho al olvido\").</li>\n      <li>Restringir el procesamiento de sus datos.</li>\n      <li>Retirar su consentimiento para el procesamiento de datos.</li>\n</ul>\n<p>Para ejercer estos derechos, contáctenos en <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>.</p>\n\n<h2>Seguridad de los datos</h2>\n<p>Tomamos medidas razonables para proteger sus datos del acceso no autorizado, pérdida o alteración. Sin embargo, la transmisión de datos a través de Internet no es completamente segura, y no podemos garantizar una protección absoluta.</p>\n\n<h2>Uso de cookies</h2>\n<p>Utilizamos cookies para operar el Sitio web y proporcionar una experiencia personalizada. Puede encontrar más información sobre las cookies y cómo gestionarlas en nuestra <a href=\"https://ciphersonline.com/es/cookie-policy\">Política de Cookies</a>.</p>\n\n<h2>Enlaces a recursos de terceros</h2>\n<p>Nuestro Sitio web puede contener enlaces a sitios de terceros. No controlamos sus políticas de privacidad y recomendamos revisar sus términos por separado.</p>\n\n<h2>Cambios en la política de privacidad</h2>\n<p>Nos reservamos el derecho de actualizar esta Política de Privacidad en cualquier momento. Cualquier cambio se publicará en esta página. Por favor, revise esta página periódicamente para mantenerse informado sobre las actualizaciones.</p>\n\n<h2>Información de contacto</h2>\n<p>Si tiene alguna pregunta sobre esta Política de Privacidad o sobre el procesamiento de sus datos, por favor contáctenos en <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a></p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (11, 'pt', 'privacy-policy', 'Política de Privacidade', '<p><strong>Última atualização:</strong> 25.12.2024</p>\n<p>O site ciphersonline.com (doravante denominado o “Site”) respeita a sua privacidade e toma todas as medidas necessárias para proteger os dados pessoais em conformidade com o Regulamento Geral de Proteção de Dados (GDPR, Regulamento (UE) 2016/679). Esta Política de Privacidade explica quais dados coletamos, como eles são utilizados e quais direitos você tem em relação aos seus dados pessoais.</p>\n\n<h2>Quem somos</h2>\n<p>\n      Controlador de Dados: BRUKVA PR <br>\n      E-mail: <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>  \n      Endereço: MITE RUŽIĆA 2, NOVI SAD, SÉRVIA\n</p>\n\n<h2>Quais dados coletamos</h2>\n<p>Podemos coletar e processar os seguintes dados:</p>\n<ul>\n      <li><strong>Dados de identificação</strong>: nome, sobrenome, e-mail, número de telefone.</li>\n      <li><strong>Dados de autorização</strong>: nome de usuário, senha (criptografada).</li>\n      <li><strong>Dados técnicos</strong>: endereço IP, dados do navegador e do dispositivo, sistema operacional, geolocalização, dados de registro.</li>\n      <li><strong>Dados de atividade</strong>: histórico de visitas, interação com o conteúdo e ações no Site.</li>\n      <li><strong>Cookies e tecnologias similares</strong>: para garantir a funcionalidade do Site e analisar o comportamento do usuário (detalhes na Política de Cookies).</li>\n</ul>\n\n<h2>Base legal para o processamento</h2>\n<p>Processamos os seus dados pessoais com base nos seguintes fundamentos legais:</p>\n<ul>\n      <li><strong>Seu consentimento</strong> – ao assinar newsletters ou se registrar no Site.</li>\n      <li><strong>Execução de contrato</strong> – o processamento de dados é necessário para fornecer serviços (por exemplo, processamento de pedidos e mensagens).</li>\n      <li><strong>Interesses legítimos</strong> – para proteger nossos direitos e interesses, garantir a segurança e melhorar o Site.</li>\n      <li><strong>Obrigações legais</strong> – quando somos obrigados a reter ou fornecer dados por lei.</li>\n</ul>\n\n<h2>Como usamos os seus dados</h2>\n<p>Utilizamos os dados pessoais para os seguintes fins:</p>\n<ul>\n      <li>Fornecer acesso ao Site e às suas funcionalidades.</li>\n      <li>Entrar em contato com você sobre consultas enviadas através de formulários no Site.</li>\n      <li>Analisar e melhorar o desempenho e a experiência do usuário no Site.</li>\n      <li>Cumprir com nossas obrigações legais e proteger contra fraudes.</li>\n</ul>\n\n<h2>Compartilhamento de dados com terceiros</h2>\n<p>Não compartilhamos seus dados pessoais com terceiros sem o seu consentimento, exceto quando exigido por lei. Seus dados podem ser transferidos para prestadores de serviços técnicos para garantir a operação do Site (por exemplo, provedores de hospedagem ou serviços de análise).</p>\n\n<h2>Período de retenção de dados</h2>\n<p>Seus dados são armazenados pelo tempo necessário para cumprir os fins do processamento ou atender às obrigações legais.</p>\n\n<h2>Seus direitos</h2>\n<p>Você tem o direito de:</p>\n<ul>\n      <li>Solicitar acesso aos seus dados pessoais.</li>\n      <li>Corrigir os seus dados.</li>\n      <li>Solicitar a exclusão dos seus dados (\"direito ao esquecimento\").</li>\n      <li>Restringir o processamento dos seus dados.</li>\n      <li>Retirar o consentimento para o processamento de dados.</li>\n</ul>\n<p>Para exercer esses direitos, entre em contato conosco pelo e-mail <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>.</p>\n\n<h2>Segurança dos dados</h2>\n<p>Tomamos medidas razoáveis para proteger os seus dados contra acesso não autorizado, perda ou alteração. No entanto, a transmissão de dados pela Internet não é completamente segura, e não podemos garantir proteção absoluta.</p>\n\n<h2>Uso de cookies</h2>\n<p>Utilizamos cookies para operar o Site e proporcionar uma experiência personalizada. Mais informações sobre cookies e como gerenciá-los podem ser encontradas em nossa <a href=\"https://ciphersonline.com/pt/cookie-policy\">Política de Cookies</a>.</p>\n\n<h2>Links para recursos de terceiros</h2>\n<p>Nosso Site pode conter links para sites de terceiros. Não controlamos suas políticas de privacidade e recomendamos que você revise seus termos separadamente.</p>\n\n<h2>Alterações na política de privacidade</h2>\n<p>Reservamo-nos o direito de atualizar esta Política de Privacidade a qualquer momento. Quaisquer alterações serão publicadas nesta página. Por favor, revise esta página periodicamente para se manter informado sobre as atualizações.</p>\n\n<h2>Informações de contato</h2>\n<p>Se você tiver alguma dúvida sobre esta Política de Privacidade ou sobre o processamento dos seus dados, entre em contato conosco pelo e-mail <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a></p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (12, 'ru', 'privacy-policy', 'Политика конфиденциальности', '<p><strong>Дата последнего обновления:</strong>25.12.2024</p>\n<p>Сайт ciphersonline.com (далее – “Сайт”) уважает вашу конфиденциальность и принимает все необходимые меры для защиты персональных данных в соответствии с Общим регламентом по защите данных (GDPR, Regulation (EU) 2016/679). Настоящая Политика конфиденциальности объясняет, какие данные мы собираем, как они используются и какие у вас есть права в отношении ваших персональных данных.</p>\n<h2>Кто мы</h2>\n<p>\n      Контроллер данных: BRUKVA PR <br>\n      Email: <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>  \n      Адрес: MITE RUŽIĆA 2, НОВИ САД, СЕРБИЯ\n</p>\n\n<h2>Какие данные мы собираем</h2>\n<p>Мы можем собирать и обрабатывать следующие данные:</p>\n<ul>\n      <li><strong>Идентификационные данные</strong>: имя, фамилия, email, телефонный номер.</li>\n      <li><strong>Данные для авторизации</strong>: логин, пароль (шифрованный).</li>\n      <li><strong>Технические данные</strong>: IP-адрес, данные о браузере и устройстве, операционная система, геолокация, данные логов.</li>\n      <li><strong>Данные об активности</strong>: история посещений, взаимодействие с контентом и действия на Сайте.</li>\n      <li><strong>Файлы cookie и аналогичные технологии</strong>: для обеспечения работы Сайта и анализа поведения пользователей (подробности в Политике использования Cookie).</li>\n</ul>\n\n<h2>Правовые основания для обработки</h2>\n<p>Мы обрабатываем ваши персональные данные на следующих правовых основаниях:</p>\n<ul>\n      <li><strong>Ваше согласие</strong> – при подписке на рассылку или при регистрации на Сайте.</li>\n      <li><strong>Выполнение договора</strong> – обработка данных необходима для предоставления услуг (например, обработка заказов и сообщений).</li>\n      <li><strong>Законные интересы</strong> – для защиты наших прав и интересов, обеспечения безопасности и улучшения работы Сайта.</li>\n      <li><strong>Юридические обязательства</strong> – когда мы обязаны сохранять или предоставлять данные по требованию закона.</li>\n</ul>\n\n<h2>Как мы используем ваши данные</h2>\n<p>Мы используем персональные данные для следующих целей:</p>\n<ul>\n      <li>Для предоставления доступа к Сайту и его функционалу.</li>\n      <li>Для связи с вами по поводу запросов, оставленных через формы на Сайте.</li>\n      <li>Для анализа и улучшения работы Сайта и пользовательского опыта.</li>\n      <li>Для соблюдения наших юридических обязательств и защиты от мошенничества.</li>\n</ul>\n\n<h2>Передача данных третьим лицам</h2>\n<p>Мы не передаём ваши персональные данные третьим лицам без вашего согласия, за исключением случаев, предусмотренных законом. Ваши данные могут быть переданы техническим подрядчикам для обеспечения работы сайта (например, хостинг-провайдеру или сервисам аналитики).</p>\n\n<h2>Срок хранения данных</h2>\n<p>Ваши данные хранятся столько, сколько необходимо для достижения целей обработки или выполнения юридических обязательств.</p>\n\n<h2>Ваши права</h2>\n<p>Вы имеете право:</p>\n<ul>\n      <li>Запросить доступ к вашим персональным данным.</li>\n      <li>Внести исправления в ваши данные.</li>\n      <li>Потребовать удаления ваших данных (\"право быть забытым\").</li>\n      <li>Ограничить обработку ваших данных.</li>\n      <li>Отозвать согласие на обработку данных.</li>\n</ul>\n<p>Для реализации этих прав свяжитесь с нами по адресу <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>.</p>\n\n<h2>Безопасность данных</h2>\n<p>Мы принимаем разумные меры для защиты ваших данных от несанкционированного доступа, потери или изменения. Однако передача данных через Интернет не является абсолютно безопасной, и мы не можем гарантировать полную защиту.</p>\n\n<h2>Использование cookie</h2>\n<p>Для работы Сайта и обеспечения персонализированного опыта мы используем cookie. Подробнее о cookie и как управлять ими – в нашей <a href=\"https://ciphersonline.com/ru/cookie-policy\">Политике использования Cookie</a>.</p>\n\n<h2>Cсылки на сторонние ресурсы</h2>\n<p>На нашем Сайте могут содержаться ссылки на сторонние сайты. Мы не контролируем их политику конфиденциальности и рекомендуем изучить их условия самостоятельно.</p>\n\n<h2>Изменения в политике конфиденциальности</h2>\n<p>Мы оставляем за собой право обновлять данную Политику конфиденциальности. Все изменения будут опубликованы на этой странице. Пожалуйста, периодически проверяйте эту страницу, чтобы быть в курсе обновлений.</p>\n\n<h2>Контактная информация</h2>\n<p>Если у вас есть вопросы по поводу настоящей Политики конфиденциальности или обработки ваших данных, свяжитесь с нами: <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a></p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (13, 'tr', 'privacy-policy', 'Gizlilik Politikası', '<p><strong>Son Güncelleme:</strong> 25.12.2024</p>\n<p>ciphersonline.com web sitesi (bundan böyle “Web Sitesi” olarak anılacaktır) gizliliğinize saygı duyar ve Kişisel Verilerin Korunması Genel Yönetmeliği\'ne (GDPR, Regulation (EU) 2016/679) uygun olarak kişisel verilerin korunması için gerekli tüm önlemleri alır. Bu Gizlilik Politikası, hangi verileri topladığımızı, bunların nasıl kullanıldığını ve kişisel verilerinizle ilgili hangi haklara sahip olduğunuzu açıklar.</p>\n\n<h2>Kim olduğumuz</h2>\n<p>\n      Veri Sorumlusu: BRUKVA PR <br>\n      E-posta: <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>  \n      Adres: MITE RUŽIĆA 2, NOVI SAD, SIRBİSTAN\n</p>\n\n<h2>Hangi verileri topluyoruz</h2>\n<p>Aşağıdaki verileri toplayabilir ve işleyebiliriz:</p>\n<ul>\n      <li><strong>Kimlik verileri</strong>: ad, soyad, e-posta, telefon numarası.</li>\n      <li><strong>Yetkilendirme verileri</strong>: kullanıcı adı, şifre (şifrelenmiş).</li>\n      <li><strong>Teknik veriler</strong>: IP adresi, tarayıcı ve cihaz bilgileri, işletim sistemi, coğrafi konum, kayıt verileri.</li>\n      <li><strong>Etkinlik verileri</strong>: ziyaret geçmişi, içerik etkileşimi ve Web Sitesi\'ndeki eylemler.</li>\n      <li><strong>Çerezler ve benzer teknolojiler</strong>: Web Sitesi\'nin işlevselliğini sağlamak ve kullanıcı davranışını analiz etmek için (detaylar Çerez Politikası\'nda bulunabilir).</li>\n</ul>\n\n<h2>Veri işleme için yasal dayanak</h2>\n<p>Kişisel verilerinizi aşağıdaki yasal dayanaklara göre işliyoruz:</p>\n<ul>\n      <li><strong>Onayınız</strong> – Web Sitesi\'ne kayıt olurken veya bülten aboneliği sırasında.</li>\n      <li><strong>Sözleşmenin ifası</strong> – veri işleme, hizmetlerin sağlanması için gereklidir (örneğin, siparişlerin ve mesajların işlenmesi).</li>\n      <li><strong>Meşru menfaatler</strong> – haklarımızı ve çıkarlarımızı korumak, güvenliği sağlamak ve Web Sitesi\'ni iyileştirmek için.</li>\n      <li><strong>Yasal yükümlülükler</strong> – verileri yasal olarak saklamamız veya sağlamamız gerektiğinde.</li>\n</ul>\n\n<h2>Verilerinizi nasıl kullanıyoruz</h2>\n<p>Kişisel verileri aşağıdaki amaçlar için kullanıyoruz:</p>\n<ul>\n      <li>Web Sitesi\'ne ve işlevlerine erişim sağlamak.</li>\n      <li>Web Sitesi\'ndeki formlar aracılığıyla gönderilen taleplerle ilgili sizinle iletişime geçmek.</li>\n      <li>Web Sitesi\'nin performansını ve kullanıcı deneyimini analiz etmek ve iyileştirmek.</li>\n      <li>Yasal yükümlülüklerimize uymak ve dolandırıcılığa karşı korunmak.</li>\n</ul>\n\n<h2>Verilerin üçüncü taraflarla paylaşılması</h2>\n<p>Kişisel verilerinizi, kanunen zorunlu olmadıkça veya sizin izniniz olmadan üçüncü taraflarla paylaşmayız. Verileriniz, Web Sitesi\'nin çalışmasını sağlamak için teknik yüklenicilere (örneğin, barındırma sağlayıcıları veya analiz hizmetleri) aktarılabilir.</p>\n\n<h2>Veri saklama süresi</h2>\n<p>Verileriniz, işleme amaçlarını gerçekleştirmek veya yasal yükümlülükleri yerine getirmek için gerekli olduğu sürece saklanır.</p>\n\n<h2>Haklarınız</h2>\n<p>Aşağıdaki haklara sahipsiniz:</p>\n<ul>\n      <li>Kişisel verilerinize erişim talep etme.</li>\n      <li>Verilerinizi düzeltme.</li>\n      <li>Verilerinizin silinmesini talep etme (\"unutulma hakkı\").</li>\n      <li>Verilerinizin işlenmesini kısıtlama.</li>\n      <li>Veri işleme izninizi geri çekme.</li>\n</ul>\n<p>Bu haklarınızı kullanmak için bizimle şu adresten iletişime geçin: <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>.</p>\n\n<h2>Veri güvenliği</h2>\n<p>Verilerinizi yetkisiz erişim, kayıp veya değişiklikten korumak için makul önlemler alıyoruz. Ancak, İnternet üzerinden veri iletimi tamamen güvenli değildir ve tam koruma sağlayabileceğimizi garanti edemeyiz.</p>\n\n<h2>Çerezlerin kullanımı</h2>\n<p>Web Sitesi\'nin çalışması ve kişiselleştirilmiş bir deneyim sağlamak için çerezleri kullanıyoruz. Çerezler hakkında daha fazla bilgi ve bunların nasıl yönetileceği konusunda detaylar <a href=\"https://ciphersonline.com/tr/cookie-policy\">Çerez Politikası</a> bölümünde bulunabilir.</p>\n\n<h2>Üçüncü taraf kaynaklarına bağlantılar</h2>\n<p>Web Sitemiz üçüncü taraf sitelere bağlantılar içerebilir. Bu sitelerin gizlilik politikalarını kontrol etmiyoruz ve şartlarını ayrı olarak incelemenizi öneririz.</p>\n\n<h2>Gizlilik politikasındaki değişiklikler</h2>\n<p>Bu Gizlilik Politikasını istediğimiz zaman güncelleme hakkımız saklıdır. Tüm değişiklikler bu sayfada yayınlanacaktır. Lütfen güncellemelerden haberdar olmak için bu sayfayı düzenli olarak kontrol edin.</p>\n\n<h2>İletişim bilgileri</h2>\n<p>Bu Gizlilik Politikası veya verilerinizin işlenmesiyle ilgili herhangi bir sorunuz varsa, lütfen bizimle şu adresten iletişime geçin: <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a></p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (14, 'fr', 'privacy-policy', 'Politique de Confidentialité', '<p><strong>Dernière mise à jour :</strong> 25.12.2024</p>\n<p>Le site web ciphersonline.com (ci-après dénommé “le Site”) respecte votre vie privée et prend toutes les mesures nécessaires pour protéger les données personnelles conformément au Règlement général sur la protection des données (RGPD, Règlement (UE) 2016/679). Cette Politique de Confidentialité explique quelles données nous collectons, comment elles sont utilisées et quels sont vos droits concernant vos données personnelles.</p>\n\n<h2>Qui nous sommes</h2>\n<p>\n      Responsable du traitement des données : BRUKVA PR <br>\n      E-mail : <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>  \n      Adresse : MITE RUŽIĆA 2, NOVI SAD, SERBIE\n</p>\n\n<h2>Quelles données nous collectons</h2>\n<p>Nous pouvons collecter et traiter les données suivantes :</p>\n<ul>\n      <li><strong>Données d\'identification</strong> : prénom, nom, e-mail, numéro de téléphone.</li>\n      <li><strong>Données d\'autorisation</strong> : nom d\'utilisateur, mot de passe (crypté).</li>\n      <li><strong>Données techniques</strong> : adresse IP, données du navigateur et de l\'appareil, système d\'exploitation, géolocalisation, données de journal.</li>\n      <li><strong>Données d\'activité</strong> : historique des visites, interaction avec le contenu et actions sur le Site.</li>\n      <li><strong>Cookies et technologies similaires</strong> : pour assurer le fonctionnement du Site et analyser le comportement des utilisateurs (détails dans la Politique de Cookies).</li>\n</ul>\n\n<h2>Base légale pour le traitement des données</h2>\n<p>Nous traitons vos données personnelles sur les bases légales suivantes :</p>\n<ul>\n      <li><strong>Votre consentement</strong> – lors de l\'inscription à des newsletters ou à l\'enregistrement sur le Site.</li>\n      <li><strong>Exécution du contrat</strong> – le traitement des données est nécessaire pour fournir des services (par exemple, le traitement des commandes et des messages).</li>\n      <li><strong>Intérêts légitimes</strong> – pour protéger nos droits et intérêts, garantir la sécurité et améliorer le Site.</li>\n      <li><strong>Obligations légales</strong> – lorsque nous sommes tenus de conserver ou de fournir des données conformément à la loi.</li>\n</ul>\n\n<h2>Comment nous utilisons vos données</h2>\n<p>Nous utilisons les données personnelles aux fins suivantes :</p>\n<ul>\n      <li>Fournir l\'accès au Site et à ses fonctionnalités.</li>\n      <li>Vous contacter concernant les demandes soumises via les formulaires sur le Site.</li>\n      <li>Analyser et améliorer les performances et l\'expérience utilisateur du Site.</li>\n      <li>Respecter nos obligations légales et nous protéger contre la fraude.</li>\n</ul>\n\n<h2>Partage des données avec des tiers</h2>\n<p>Nous ne partageons pas vos données personnelles avec des tiers sans votre consentement, sauf si la loi l\'exige. Vos données peuvent être transférées à des prestataires techniques pour assurer le bon fonctionnement du Site (par exemple, fournisseurs d\'hébergement ou services d\'analyse).</p>\n\n<h2>Durée de conservation des données</h2>\n<p>Vos données sont conservées aussi longtemps que nécessaire pour atteindre les objectifs de traitement ou pour répondre aux obligations légales.</p>\n\n<h2>Vos droits</h2>\n<p>Vous avez le droit de :</p>\n<ul>\n      <li>Demander l\'accès à vos données personnelles.</li>\n      <li>Corriger vos données.</li>\n      <li>Demander la suppression de vos données (\"droit à l\'oubli\").</li>\n      <li>Limiter le traitement de vos données.</li>\n      <li>Retirer votre consentement au traitement des données.</li>\n</ul>\n<p>Pour exercer ces droits, contactez-nous à l\'adresse suivante : <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>.</p>\n\n<h2>Sécurité des données</h2>\n<p>Nous prenons des mesures raisonnables pour protéger vos données contre tout accès non autorisé, perte ou modification. Cependant, la transmission de données sur Internet n\'est pas entièrement sécurisée et nous ne pouvons garantir une protection absolue.</p>\n\n<h2>Utilisation des cookies</h2>\n<p>Nous utilisons des cookies pour faire fonctionner le Site et offrir une expérience personnalisée. Vous pouvez en savoir plus sur les cookies et la manière de les gérer dans notre <a href=\"https://ciphersonline.com/fr/cookie-policy\">Politique de Cookies</a>.</p>\n\n<h2>Liens vers des ressources tierces</h2>\n<p>Notre Site peut contenir des liens vers des sites tiers. Nous ne contrôlons pas leurs politiques de confidentialité et nous vous recommandons de lire leurs conditions séparément.</p>\n\n<h2>Modifications de la politique de confidentialité</h2>\n<p>Nous nous réservons le droit de mettre à jour cette Politique de Confidentialité à tout moment. Toute modification sera publiée sur cette page. Veuillez consulter cette page périodiquement pour rester informé des mises à jour.</p>\n\n<h2>Informations de contact</h2>\n<p>Si vous avez des questions concernant cette Politique de Confidentialité ou le traitement de vos données, veuillez nous contacter à l\'adresse suivante : <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a></p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (15, 'de', 'privacy-policy', 'Datenschutzrichtlinie', '<p><strong>Letzte Aktualisierung:</strong> 25.12.2024</p>\n<p>Die Website ciphersonline.com (nachfolgend als “die Website” bezeichnet) respektiert Ihre Privatsphäre und ergreift alle erforderlichen Maßnahmen zum Schutz personenbezogener Daten gemäß der Datenschutz-Grundverordnung (DSGVO, Verordnung (EU) 2016/679). Diese Datenschutzerklärung erklärt, welche Daten wir erheben, wie sie verwendet werden und welche Rechte Sie in Bezug auf Ihre personenbezogenen Daten haben.</p>\n\n<h2>Wer wir sind</h2>\n<p>\n      Verantwortlicher für die Datenverarbeitung: BRUKVA PR <br>\n      E-Mail: <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>  \n      Adresse: MITE RUŽIĆA 2, NOVI SAD, SERBIEN\n</p>\n\n<h2>Welche Daten wir erheben</h2>\n<p>Wir können die folgenden Daten erheben und verarbeiten:</p>\n<ul>\n      <li><strong>Identifikationsdaten</strong>: Vorname, Nachname, E-Mail, Telefonnummer.</li>\n      <li><strong>Autorisierungsdaten</strong>: Benutzername, Passwort (verschlüsselt).</li>\n      <li><strong>Technische Daten</strong>: IP-Adresse, Browser- und Gerätedaten, Betriebssystem, Standortdaten, Protokolldaten.</li>\n      <li><strong>Aktivitätsdaten</strong>: Besuchsverlauf, Interaktionen mit Inhalten und Aktivitäten auf der Website.</li>\n      <li><strong>Cookies und ähnliche Technologien</strong>: zur Gewährleistung der Funktionalität der Website und zur Analyse des Benutzerverhaltens (Details in der Cookie-Richtlinie).</li>\n</ul>\n\n<h2>Rechtsgrundlage für die Verarbeitung</h2>\n<p>Wir verarbeiten Ihre personenbezogenen Daten auf folgenden rechtlichen Grundlagen:</p>\n<ul>\n      <li><strong>Ihre Einwilligung</strong> – wenn Sie sich für Newsletter anmelden oder auf der Website registrieren.</li>\n      <li><strong>Vertragserfüllung</strong> – die Verarbeitung der Daten ist notwendig, um Dienstleistungen bereitzustellen (z.B. Bearbeitung von Bestellungen und Nachrichten).</li>\n      <li><strong>Berechtigte Interessen</strong> – zum Schutz unserer Rechte und Interessen, zur Gewährleistung der Sicherheit und zur Verbesserung der Website.</li>\n      <li><strong>Gesetzliche Verpflichtungen</strong> – wenn wir gesetzlich verpflichtet sind, Daten zu speichern oder bereitzustellen.</li>\n</ul>\n\n<h2>Wie wir Ihre Daten verwenden</h2>\n<p>Wir verwenden personenbezogene Daten zu folgenden Zwecken:</p>\n<ul>\n      <li>Zur Bereitstellung des Zugangs zur Website und deren Funktionen.</li>\n      <li>Zur Kontaktaufnahme mit Ihnen bezüglich Anfragen, die über Formulare auf der Website eingereicht wurden.</li>\n      <li>Zur Analyse und Verbesserung der Leistung und Benutzererfahrung der Website.</li>\n      <li>Zur Erfüllung unserer gesetzlichen Verpflichtungen und zum Schutz vor Betrug.</li>\n</ul>\n\n<h2>Weitergabe von Daten an Dritte</h2>\n<p>Wir geben Ihre personenbezogenen Daten nicht ohne Ihre Zustimmung an Dritte weiter, es sei denn, dies ist gesetzlich vorgeschrieben. Ihre Daten können an technische Dienstleister zur Gewährleistung des Betriebs der Website (z.B. Hosting-Anbieter oder Analysedienste) weitergegeben werden.</p>\n\n<h2>Speicherdauer der Daten</h2>\n<p>Ihre Daten werden so lange gespeichert, wie es zur Erfüllung der Verarbeitungszwecke oder zur Einhaltung gesetzlicher Verpflichtungen erforderlich ist.</p>\n\n<h2>Ihre Rechte</h2>\n<p>Sie haben das Recht:</p>\n<ul>\n      <li>Zugang zu Ihren personenbezogenen Daten zu beantragen.</li>\n      <li>Ihre Daten zu berichtigen.</li>\n      <li>Die Löschung Ihrer Daten zu verlangen (\"Recht auf Vergessenwerden\").</li>\n      <li>Die Verarbeitung Ihrer Daten einzuschränken.</li>\n      <li>Ihre Einwilligung zur Datenverarbeitung zu widerrufen.</li>\n</ul>\n<p>Um diese Rechte auszuüben, kontaktieren Sie uns bitte unter <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>.</p>\n\n<h2>Datensicherheit</h2>\n<p>Wir ergreifen angemessene Maßnahmen, um Ihre Daten vor unbefugtem Zugriff, Verlust oder Veränderung zu schützen. Die Datenübertragung im Internet ist jedoch nicht vollständig sicher, und wir können keinen absoluten Schutz garantieren.</p>\n\n<h2>Verwendung von Cookies</h2>\n<p>Wir verwenden Cookies, um den Betrieb der Website sicherzustellen und eine personalisierte Erfahrung zu bieten. Weitere Informationen zu Cookies und deren Verwaltung finden Sie in unserer <a href=\"https://ciphersonline.com/de/cookie-policy\">Cookie-Richtlinie</a>.</p>\n\n<h2>Links zu Drittanbieter-Ressourcen</h2>\n<p>Unsere Website kann Links zu Websites Dritter enthalten. Wir kontrollieren deren Datenschutzrichtlinien nicht und empfehlen, deren Bedingungen separat zu prüfen.</p>\n\n<h2>Änderungen der Datenschutzerklärung</h2>\n<p>Wir behalten uns das Recht vor, diese Datenschutzerklärung jederzeit zu aktualisieren. Alle Änderungen werden auf dieser Seite veröffentlicht. Bitte überprüfen Sie diese Seite regelmäßig, um über Aktualisierungen informiert zu bleiben.</p>\n\n<h2>Kontaktinformationen</h2>\n<p>Wenn Sie Fragen zu dieser Datenschutzerklärung oder zur Verarbeitung Ihrer Daten haben, kontaktieren Sie uns bitte unter <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a></p>', 1);
INSERT INTO `system_pages` (`id`, `language`, `alias`, `name`, `text`, `published`) VALUES (16, 'it', 'privacy-policy', 'Informativa sulla Privacy', '<p><strong>Ultimo aggiornamento:</strong> 25.12.2024</p>\n<p>Il sito web ciphersonline.com (di seguito denominato “il Sito”) rispetta la tua privacy e adotta tutte le misure necessarie per proteggere i dati personali in conformità con il Regolamento generale sulla protezione dei dati (GDPR, Regolamento (UE) 2016/679). Questa Informativa sulla Privacy spiega quali dati raccogliamo, come vengono utilizzati e quali sono i tuoi diritti in merito ai tuoi dati personali.</p>\n\n<h2>Chi siamo</h2>\n<p>\n      Titolare del trattamento dei dati: BRUKVA PR <br>\n      E-mail: <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>  \n      Indirizzo: MITE RUŽIĆA 2, NOVI SAD, SERBIA\n</p>\n\n<h2>Quali dati raccogliamo</h2>\n<p>Possiamo raccogliere e trattare i seguenti dati:</p>\n<ul>\n      <li><strong>Dati identificativi</strong>: nome, cognome, e-mail, numero di telefono.</li>\n      <li><strong>Dati di autorizzazione</strong>: nome utente, password (criptata).</li>\n      <li><strong>Dati tecnici</strong>: indirizzo IP, dati del browser e del dispositivo, sistema operativo, geolocalizzazione, dati di log.</li>\n      <li><strong>Dati di attività</strong>: cronologia delle visite, interazione con i contenuti e azioni sul Sito.</li>\n      <li><strong>Cookie e tecnologie simili</strong>: per garantire la funzionalità del Sito e analizzare il comportamento degli utenti (dettagli nella Politica sui Cookie).</li>\n</ul>\n\n<h2>Base giuridica per il trattamento dei dati</h2>\n<p>Trattiamo i tuoi dati personali in base ai seguenti fondamenti giuridici:</p>\n<ul>\n      <li><strong>Il tuo consenso</strong> – al momento dell\'iscrizione alle newsletter o della registrazione sul Sito.</li>\n      <li><strong>Esecuzione di un contratto</strong> – il trattamento dei dati è necessario per fornire servizi (ad esempio, elaborazione di ordini e messaggi).</li>\n      <li><strong>Interessi legittimi</strong> – per proteggere i nostri diritti e interessi, garantire la sicurezza e migliorare il Sito.</li>\n      <li><strong>Obblighi legali</strong> – quando siamo obbligati a conservare o fornire dati come richiesto dalla legge.</li>\n</ul>\n\n<h2>Come utilizziamo i tuoi dati</h2>\n<p>Utilizziamo i dati personali per i seguenti scopi:</p>\n<ul>\n      <li>Per fornire accesso al Sito e alle sue funzionalità.</li>\n      <li>Per contattarti in merito a richieste inviate tramite i moduli presenti sul Sito.</li>\n      <li>Per analizzare e migliorare le prestazioni e l\'esperienza utente del Sito.</li>\n      <li>Per adempiere ai nostri obblighi legali e proteggere da frodi.</li>\n</ul>\n\n<h2>Condivisione dei dati con terze parti</h2>\n<p>Non condividiamo i tuoi dati personali con terze parti senza il tuo consenso, salvo quando richiesto dalla legge. I tuoi dati possono essere trasferiti a fornitori di servizi tecnici per garantire il funzionamento del Sito (ad esempio, fornitori di hosting o servizi di analisi).</p>\n\n<h2>Periodo di conservazione dei dati</h2>\n<p>I tuoi dati vengono conservati per il tempo necessario a raggiungere gli scopi del trattamento o per adempiere agli obblighi legali.</p>\n\n<h2>I tuoi diritti</h2>\n<p>Hai il diritto di:</p>\n<ul>\n      <li>Richiedere l\'accesso ai tuoi dati personali.</li>\n      <li>Correggere i tuoi dati.</li>\n      <li>Richiedere la cancellazione dei tuoi dati (\"diritto all\'oblio\").</li>\n      <li>Limitare il trattamento dei tuoi dati.</li>\n      <li>Revocare il consenso al trattamento dei dati.</li>\n</ul>\n<p>Per esercitare questi diritti, contattaci all\'indirizzo <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a>.</p>\n\n<h2>Sicurezza dei dati</h2>\n<p>Adottiamo misure ragionevoli per proteggere i tuoi dati da accessi non autorizzati, perdita o alterazione. Tuttavia, la trasmissione di dati su Internet non è completamente sicura e non possiamo garantire una protezione assoluta.</p>\n\n<h2>Uso dei cookie</h2>\n<p>Utilizziamo i cookie per il funzionamento del Sito e per fornire un\'esperienza personalizzata. Maggiori informazioni sui cookie e su come gestirli sono disponibili nella nostra <a href=\"https://ciphersonline.com/it/cookie-policy\">Politica sui Cookie</a>.</p>\n\n<h2>Collegamenti a risorse di terze parti</h2>\n<p>Il nostro Sito può contenere collegamenti a siti di terze parti. Non controlliamo le loro politiche sulla privacy e ti consigliamo di leggere i loro termini separatamente.</p>\n\n<h2>Modifiche alla politica sulla privacy</h2>\n<p>Ci riserviamo il diritto di aggiornare questa Politica sulla Privacy in qualsiasi momento. Qualsiasi modifica verrà pubblicata su questa pagina. Ti invitiamo a controllare periodicamente questa pagina per rimanere informato sugli aggiornamenti.</p>\n\n<h2>Informazioni di contatto</h2>\n<p>Se hai domande in merito a questa Politica sulla Privacy o al trattamento dei tuoi dati, ti invitiamo a contattarci all\'indirizzo <a href=\"mailto:contact@ciphersonline.com\">contact@ciphersonline.com</a></p>', 1);
COMMIT;

SET FOREIGN_KEY_CHECKS = 1;
